func TestApplyFieldOverridersLogsPatchType(t *testing.T) {
	tests := []struct {
		name        string
		overrider   policyv1alpha1.FieldOverrider
		wantLog     string
		unwantedLog string
	}{
		{
			name: "yaml patch failure logs yaml",
			overrider: policyv1alpha1.FieldOverrider{
				FieldPath: "/data/config.yaml",
				YAML: []policyv1alpha1.YAMLPatchOperation{
					{SubPath: "/missing", Operator: policyv1alpha1.OverriderOpReplace, Value: apiextensionsv1.JSON{Raw: []byte(`"updated"`)}},
				},
			},
			wantLog:     "Error applying raw YAML patch",
			unwantedLog: "Error applying raw JSON patch",
		},
		{
			name: "json patch failure logs json",
			overrider: policyv1alpha1.FieldOverrider{
				FieldPath: "/data/config.json",
				JSON: []policyv1alpha1.JSONPatchOperation{
					{SubPath: "/missing", Operator: policyv1alpha1.OverriderOpReplace, Value: apiextensionsv1.JSON{Raw: []byte(`"updated"`)}},
				},
			},
			wantLog:     "Error applying raw JSON patch",
			unwantedLog: "Error applying raw YAML patch",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			obj := &unstructured.Unstructured{Object: map[string]interface{}{
				"data": map[string]interface{}{
					"config.yaml": "key: value\n",
					"config.json": `{"key":"value"}`,
				},
			}}
			var logBuffer bytes.Buffer
			klog.SetOutput(&logBuffer)
			t.Cleanup(func() { klog.SetOutput(nil) })

			err := applyFieldOverriders(obj, []policyv1alpha1.FieldOverrider{tt.overrider})
			if err == nil {
				t.Fatalf("applyFieldOverriders() expected error")
			}
			logs := logBuffer.String()
			if !strings.Contains(logs, tt.wantLog) {
				t.Fatalf("applyFieldOverriders() logs = %q, want %q", logs, tt.wantLog)
			}
			if strings.Contains(logs, tt.unwantedLog) {
				t.Fatalf("applyFieldOverriders() logs = %q, did not want %q", logs, tt.unwantedLog)
			}
		})
	}
}

func TestApplyFieldOverridersEmptyPatchErrors(t *testing.T) {
	obj := &unstructured.Unstructured{Object: map[string]interface{}{
		"data": map[string]interface{}{
			"config": "keep-me",
		},
	}}

	err := applyFieldOverriders(obj, []policyv1alpha1.FieldOverrider{{FieldPath: "/data/config"}})
	if err == nil {
		t.Fatalf("applyFieldOverriders() expected error")
	}
	if got := obj.Object["data"].(map[string]interface{})["config"]; got != "keep-me" {
		t.Fatalf("applyFieldOverriders() changed data to %v, want keep-me", got)
	}
}

